import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { z } from "zod";

const server = new McpServer({ name: "my-server", version: "1.0.0" });

// Zod schema infers the TypeScript type for arguments
server.tool(
  "ping",
  "Return pong",
  {},   // empty input schema
  async () => ({
    content: [{ type: "text", text: "pong" }],
  })
);

server.tool(
  "add",
  "Add two numbers",
  { a: z.number(), b: z.number() },
  async ({ a, b }) => ({
    content: [{ type: "text", text: String(a + b) }],
  })
);

const transport = new StdioServerTransport();
await server.connect(transport);

import { Client } from "@modelcontextprotocol/sdk/client/index.js";
import { StdioClientTransport } from "@modelcontextprotocol/sdk/client/stdio.js";

const transport = new StdioClientTransport({
  command: "node",
  args: ["server.js"],
});

const client = new Client({ name: "my-client", version: "1.0.0" });
await client.connect(transport);

const tools = await client.listTools();
console.log(tools.tools.map((t) => t.name));

const result = await client.callTool({ name: "add", arguments: { a: 3, b: 4 } });
console.log(result.content[0].text);   // "7"

await client.close();

import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { z } from "zod";
import fetch from "node-fetch";

const server = new McpServer({ name: "weather", version: "1.0.0" });

server.tool(
  "get_weather",
  "Fetch weather for a city",
  { city: z.string() },
  async ({ city }) => {
    const url = `https://wttr.in/${encodeURIComponent(city)}?format=j1`;
    const resp = await fetch(url);
    if (!resp.ok) {
      return {
        content: [{ type: "text", text: `Error: ${resp.status} ${resp.statusText}` }],
        isError: true,
      };
    }
    const data = (await resp.json()) as any;
    const current = data.current_condition?.[0];
    const summary = `${city}: ${current?.weatherDesc?.[0]?.value}, ${current?.temp_C}°C`;
    return {
      content: [
        { type: "text", text: summary },
        { type: "text", text: JSON.stringify(current, null, 2) },
      ],
    };
  }
);

import { McpServer, ResourceTemplate } from "@modelcontextprotocol/sdk/server/mcp.js";

const server = new McpServer({ name: "docs", version: "1.0.0" });

// Template: docs://pages/{slug}
server.resource(
  "page",
  new ResourceTemplate("docs://pages/{slug}", { list: undefined }),
  async (uri, { slug }) => ({
    contents: [
      {
        uri: uri.href,
        mimeType: "text/markdown",
        text: `# ${slug}\n\nContent for ${slug}.`,
      },
    ],
  })
);
